    <script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
    <script>
        function confirmarTramite(nivel) {
            Swal.fire({
                title: '¿Estás seguro?',
                text: `¿DESEAS REGISTRAR ${nivel}?`,
                icon: 'warning',
                showCancelButton: true,
                confirmButtonColor: '#94c93b',
                cancelButtonColor: '#faa625',
                confirmButtonText: 'SI, CONTINUAR',
                cancelButtonText: 'CANCELAR'
            }).then((result) => {
                if (result.isConfirmed) {
                    document.getElementById('nivelprocedimiento').value = nivel;
                    document.getElementById('formTramite2').submit();
                }
            });
        }
        document.addEventListener('DOMContentLoaded', function () {
            @if(session('success'))
                Swal.fire({
                    title: '¡Guardado!',
                    text: "{{ session('success') }}",
                    icon: 'success',
                    confirmButtonColor: '#94c93b',
                    confirmButtonText: 'ACEPTAR'
                });
            @endif
        });
    </script>
    
