                                                                <button type="button" class="btn btn-danger btn-sm removeRowBtn"><i class="fas fa-trash"></i></button>
                                                            </td>
                                                        `;
                                                        tbody.appendChild(row);

                                                        row.querySelector(".removeRowBtn").addEventListener("click", function () {
                                                            row.remove();
                                                        });
                                                    }

                                                    if (addRowBtn) {
