                                                                                let td = this.closest('td');
                                                                                let select = td.querySelector('.nrselecarea3');
                                                                                let input  = td.querySelector('.nrcorsol3');
                                                                                let seleccion = select.value;
                                                                                if (input.value.trim() === "") {
                                                                                    input.value = seleccion;
                                                                                } else {
                                                                                    input.value = input.value + ", " + seleccion;
                                                                                }
                                                                                input.focus();
                                                                                input.setSelectionRange(input.value.length, input.value.length);
                                                                            });
                                                                        });
                                                                    });
