                <script>
                    function guardarAmbos() {
                        let btn = document.getElementById('btnGuardarTodo');
                        btn.disabled = true;
                        btn.innerText = 'Guardando...';

                        let form1 = document.getElementById('formTramite22');
                        let form2 = document.getElementById('formCriterios');

                        let data1 = new FormData(form1);
                        let data2 = new FormData(form2);

                        fetch(form1.action, {
                            method: 'POST',
                            body: data1,
                            headers: {'X-CSRF-TOKEN': '{{ csrf_token() }}'}
                        })
                        .then(() => {
                            return fetch(form2.action, {
                                method: 'POST',
                                body: data2,
                                headers: {'X-CSRF-TOKEN': '{{ csrf_token() }}'}
                            });
                        })
                        .then(() => {
                            alert('¡DICTAMEN GUARDADO EXITOSAMENTE!');
                            location.reload();
                        })
                        .catch(err => {
                            console.error(err);
                            btn.disabled = false;
                            btn.innerText = 'GUARDAR TODO';
                        });
                    }
                </script>
            </div>
        </div>
    </div>
